// Range represents a continuous range of starting indices i.
type Range struct {
	Start int
	End   int
}

// mergeRanges takes a set of existing ranges and a new range, and returns a minimal,
// sorted, non-overlapping set of ranges covering all input ranges.
func mergeRanges(ranges []Range, newRange Range) []Range {
	if newRange.Start > newRange.End {
		return ranges // Invalid new range
	}

	// Collect all ranges and sort them by start time
	allRanges := make([]Range, len(ranges)+1)
	copy(allRanges, ranges)
	allRanges[len(ranges)] = newRange

	sort.Slice(allRanges, func(i, j int) bool {
		return allRanges[i].Start < allRanges[j].Start
	})

	merged := []Range{}
	if len(allRanges) == 0 {
		return merged
	}

	current := allRanges[0]
	for i := 1; i < len(allRanges); i++ {
		next := allRanges[i]

		// Check for overlap or adjacency (next starts at current.End + 1 or earlier)
		if next.Start <= current.End+1 {
			// Merge: extend the end
			if next.End > current.End {
				current.End = next.End
			}
		} else {
			// No overlap/adjacency, finalize current and start a new one
			merged = append(merged, current)
			current = next
		}
	}
	merged = append(merged, current)
	return merged
}

func solve(nums []int64) int64 {
	N := len(nums)
	if N == 0 {
		return 0
	}

	// M: map[OR_Value] []Ranges. Stores M_j, mapping OR value to list of start index ranges i such that OR(nums[i..j]) = OR_Value.
	M := make(map[int64][]Range)

	// FirstOccurrence[Value] stores the smallest index k <= j such that nums[k] = Value.
	FirstOccurrence := make(map[int64]int)

	var totalCount int64 = 0

	for j := 0; j < N; j++ {
		n := nums[j]
		M_next := make(map[int64][]Range)

		// 1. Extend previous subarrays (from j-1 to j)
		for O_old, Ranges_old := range M {
			O_new := O_old | n

			// Merge existing ranges for O_new in M_next with Ranges_old
			currentRanges, exists := M_next[O_new]
			if !exists {
				currentRanges = []Range{}
			}

			M_next[O_new] = mergeRanges(currentRanges, Ranges_old)
		}

		// 2. Handle subarray [nums[j]]
		O_new := n
		currentRanges, exists := M_next[O_new]
		if !exists {
			currentRanges = []Range{}
		}
		M_next[O_new] = mergeRanges(currentRanges, Range{Start: j, End: j})

		// 3. Count good subarrays ending at j
		countJ := int64(0)

		// Update FirstOccurrence for the current element
		if _, found := FirstOccurrence[n]; !found {
			FirstOccurrence[n] = j
