	N := len(nums)

	// 1. Precompute position map P: Value -> sorted list of indices where it appears.
	P := make(map[int64][]int)
	for k, val := range nums {
		P[val] = append(P[val], k)
	}

	// Helper function to check if value O exists in the subarray nums[i..j]
	checkPresence := func(O int64, i, j int) bool {
		indices, ok := P[O]
		if !ok {
			return false
		}
		// Find the index of the first element >= i in indices
		idx := sort.SearchInts(indices, i)

		if idx < len(indices) {
			k := indices[idx]
			// If this found index k is within the range [i, j], O is present.
			return k <= j
		}
		return false
	}

	totalCount := int64(0)
	// currentORs maps OR_value (int64) -> smallest starting index i (int) for subarrays ending at j-1
	currentORs := make(map[int64]int)

	// Iterate through the array, fixing the end index j
	for j := 0; j < N; j++ {
		Nj := nums[j]
		nextORs := make(map[int64]int)

		// Case 1: Subarray [j, j]. OR is Nj. Always good since Nj is present.
		totalCount++
		nextORs[Nj] = j

		// Case 2: Extend subarrays ending at j-1
		for O, i := range currentORs {
			OPrime := O | Nj

			// Subarray [i, j]. Check if OPrime is present in nums[i..j].
			if checkPresence(OPrime, i, j) {
				totalCount++
