type Range struct {
    O int64
    Start int
    End int
}

func solve(nums []int64) int64 {
    N := len(nums)
    if N == 0 {
        return 0
    }

    // 1. Preprocess valueIndices: map value -> sorted list of indices where it appears
    valueIndices := make(map[int64][]int)
    for i, val := range nums {
        valueIndices[val] = append(valueIndices[val], i)
    }

    totalGoodSubarrays := int64(0)

    // R_prev stores the ranges for endpoint j-1.
    // Sorted by Start descending.
    R_prev := []Range{}

    // Helper function to check if target O exists in nums[i_start...j]
    checkPresence := func(O int64, i_start int, j int) bool {
        indices, ok := valueIndices[O]
        if !ok || len(indices) == 0 {
            return false
        }

        // Find the smallest index k in 'indices' such that k >= i_start
        // sort.SearchInts returns the index where i_start would be inserted to maintain order.
        idx := sort.SearchInts(indices, i_start)

        if idx < len(indices) {
            k := indices[idx]
            // Check if this smallest qualifying index k is within the range [i_start, j]
            return k <= j
        }
        return false
    }

    for j := 0; j < N; j++ {
        x := nums[j]
        R_temp := []Range{}

        // 2. Calculate R_temp (ranges for endpoint j)

        // Case 1: Subarray [j, j]
        R_temp = append(R_temp, Range{O: x, Start: j, End: j})

        // Case 2: Extend previous ranges
        for _, r := range R_prev {
            O_prime := r.O | x
            // The range [r.Start, r.End] when extended ends at j
            R_temp = append(R_temp, Range{O: O_prime, Start: r.Start, End: j})
        }

        // 3. Merge R_temp into R_curr

        // Sort by Start descending
        sort.Slice(R_temp, func(i, j int) bool {
            return R_temp[i].Start > R_temp[j].Start
        })

        R_curr := []Range{}
        if len(R_temp) > 0 {
            current := R_temp[0]

            for k := 1; k < len(R_temp); k++ {
                next := R_temp[k]

                // Check for merge condition: same OR value AND contiguous starting indices
                // Since we sorted by Start descending, next.Start should be current.Start - 1
                if next.O == current.O && next.Start == current.Start - 1 {
                    // Merge: extend the end of the current range
                    current.End = next.End // Since all ranges end at j, this is redundant but conceptually sound
                } else {
                    // Finalize current range and start a new one
                    R_curr = append(R_curr, current)
                    current = next
                }
            }
            // Append the last processed range
            R_curr = append(R_curr, current)
        }

        // 4. Count good subarrays for endpoint j
        for _, r := range R_curr {
            O := r.O
            i_start := r.Start
            i_end := r.End // which is j

            if checkPresence(O, i_start, i_end) {
                // All subarrays starting in [i_start, i_end] and ending at j are good
                count := int64(i_end - i_start + 1)
                totalGoodSubarrays += count
            }
        }

        R_prev = R_curr
    }

    return totalGoodSubarrays
}

